[DataContract]
public final class SalesPackingSlipLineBusinessEventContract
{
    private ItemId          itemId;
    private Qty             qty;
    private AmountCur       amount;
    private CurrencyCode    currencyCode;

}

Method.Source:
public static SalesPackingSlipLineBusinessEventContract construct(ItemId _itemId, Qty _qty, AmountCur _amount, CurrencyCode _currencyCode)
{
    SalesPackingSlipLineBusinessEventContract contract = new SalesPackingSlipLineBusinessEventContract();
    contract.parmItemId(_itemId);
    contract.parmQty(_qty);
    contract.parmAmount(_amount);
    contract.parmCurrencyCode(_currencyCode);
    return contract;
}

[DataMember('Item Id'), BusinessEventsDataMember('Item ID')]
public ItemId parmItemId(ItemId _itemId = itemId)
{
    itemId = _itemId;
    return itemId;
}

[DataMember('Quantity'), BusinessEventsDataMember('Quantity')]
public Qty parmQty(Qty _qty = qty)
{
    qty = _qty;
    return qty;
}

[DataMember('Amount'), BusinessEventsDataMember('Line Amount')]
public AmountCur parmAmount(AmountCur _amount = amount)
{
    amount = _amount;
    return amount;
}

[DataMember('Currency'), BusinessEventsDataMember('Currency')]
public CurrencyCode parmCurrencyCode(CurrencyCode _currencyCode = currencyCode)
{
    currencyCode = _currencyCode;
    return currencyCode;
}
